import{_ as o,o as r,c as t,ag as n}from"./chunks/framework.DCk0k6gb.js";const g=JSON.parse('{"title":"SaToken Error Reference","description":"","frontmatter":{},"headers":[],"relativePath":"reference/error-reference.md","filePath":"reference/error-reference.md"}'),i={name:"reference/error-reference.md"};function a(s,e,l,u,d,h){return r(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="satoken-error-reference" tabindex="-1">SaToken Error Reference <a class="header-anchor" href="#satoken-error-reference" aria-label="Permalink to &quot;SaToken Error Reference&quot;">​</a></h1><h2 id="english" tabindex="-1">English <a class="header-anchor" href="#english" aria-label="Permalink to &quot;English&quot;">​</a></h2><h3 id="error-categories" tabindex="-1">Error Categories <a class="header-anchor" href="#error-categories" aria-label="Permalink to &quot;Error Categories&quot;">​</a></h3><p>sa-token-rust provides 32 error types organized into 10 categories:</p><h4 id="_1-basic-token-errors" tabindex="-1">1. Basic Token Errors <a class="header-anchor" href="#_1-basic-token-errors" aria-label="Permalink to &quot;1. Basic Token Errors&quot;">​</a></h4><h5 id="tokennotfound" tabindex="-1">TokenNotFound <a class="header-anchor" href="#tokennotfound" aria-label="Permalink to &quot;TokenNotFound&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Token not found or expired&quot;</li><li><strong>Description</strong>: The requested token does not exist in storage or has expired</li><li><strong>Common Causes</strong>: Token was never created, expired naturally, or manually deleted</li><li><strong>Solution</strong>: User needs to log in again to obtain a new token</li></ul><h5 id="invalidtoken" tabindex="-1">InvalidToken <a class="header-anchor" href="#invalidtoken" aria-label="Permalink to &quot;InvalidToken&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Token is invalid: {reason}&quot;</li><li><strong>Description</strong>: The token format or content is invalid</li><li><strong>Common Causes</strong>: Corrupted token, tampered token, or wrong token format</li><li><strong>Solution</strong>: Verify token integrity and ensure correct token format</li></ul><h5 id="tokenexpired" tabindex="-1">TokenExpired <a class="header-anchor" href="#tokenexpired" aria-label="Permalink to &quot;TokenExpired&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Token has expired&quot;</li><li><strong>Description</strong>: The token has passed its expiration time</li><li><strong>Common Causes</strong>: Token timeout exceeded configured duration</li><li><strong>Solution</strong>: Use refresh token to get a new access token or re-authenticate</li></ul><h4 id="_2-authentication-errors" tabindex="-1">2. Authentication Errors <a class="header-anchor" href="#_2-authentication-errors" aria-label="Permalink to &quot;2. Authentication Errors&quot;">​</a></h4><h5 id="notlogin" tabindex="-1">NotLogin <a class="header-anchor" href="#notlogin" aria-label="Permalink to &quot;NotLogin&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;User not logged in&quot;</li><li><strong>Description</strong>: User is attempting to access a protected resource without authentication</li><li><strong>Common Causes</strong>: No token provided, token not found in request</li><li><strong>Solution</strong>: User must log in first to obtain a valid token</li></ul><h4 id="_3-authorization-errors" tabindex="-1">3. Authorization Errors <a class="header-anchor" href="#_3-authorization-errors" aria-label="Permalink to &quot;3. Authorization Errors&quot;">​</a></h4><h5 id="permissiondenied" tabindex="-1">PermissionDenied <a class="header-anchor" href="#permissiondenied" aria-label="Permalink to &quot;PermissionDenied&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Permission denied: missing permission &#39;{permission}&#39;&quot;</li><li><strong>Description</strong>: User lacks the required permission to perform the action</li><li><strong>Common Causes</strong>: Insufficient permissions assigned to the user</li><li><strong>Solution</strong>: Grant the required permission to the user or role</li></ul><h5 id="roledenied" tabindex="-1">RoleDenied <a class="header-anchor" href="#roledenied" aria-label="Permalink to &quot;RoleDenied&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Role denied: missing role &#39;{role}&#39;&quot;</li><li><strong>Description</strong>: User does not have the required role</li><li><strong>Common Causes</strong>: User not assigned to the necessary role</li><li><strong>Solution</strong>: Assign the required role to the user</li></ul><h4 id="_4-account-status-errors" tabindex="-1">4. Account Status Errors <a class="header-anchor" href="#_4-account-status-errors" aria-label="Permalink to &quot;4. Account Status Errors&quot;">​</a></h4><h5 id="accountbanned" tabindex="-1">AccountBanned <a class="header-anchor" href="#accountbanned" aria-label="Permalink to &quot;AccountBanned&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Account is banned until {time}&quot;</li><li><strong>Description</strong>: The account has been temporarily or permanently banned</li><li><strong>Common Causes</strong>: Violation of terms, security issues, or administrative action</li><li><strong>Solution</strong>: Wait until ban expires or contact administrator</li></ul><h5 id="accountkickedout" tabindex="-1">AccountKickedOut <a class="header-anchor" href="#accountkickedout" aria-label="Permalink to &quot;AccountKickedOut&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Account is kicked out&quot;</li><li><strong>Description</strong>: User session has been forcefully terminated</li><li><strong>Common Causes</strong>: Administrator kicked the user, concurrent login on another device</li><li><strong>Solution</strong>: User needs to log in again</li></ul><h4 id="_5-session-errors" tabindex="-1">5. Session Errors <a class="header-anchor" href="#_5-session-errors" aria-label="Permalink to &quot;5. Session Errors&quot;">​</a></h4><h5 id="sessionnotfound" tabindex="-1">SessionNotFound <a class="header-anchor" href="#sessionnotfound" aria-label="Permalink to &quot;SessionNotFound&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Session not found&quot;</li><li><strong>Description</strong>: The session does not exist or has been deleted</li><li><strong>Common Causes</strong>: Session expired, manually deleted, or never created</li><li><strong>Solution</strong>: Establish a new session by logging in</li></ul><h4 id="_6-nonce-errors" tabindex="-1">6. Nonce Errors <a class="header-anchor" href="#_6-nonce-errors" aria-label="Permalink to &quot;6. Nonce Errors&quot;">​</a></h4><h5 id="noncealreadyused" tabindex="-1">NonceAlreadyUsed <a class="header-anchor" href="#noncealreadyused" aria-label="Permalink to &quot;NonceAlreadyUsed&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Nonce has been used, possible replay attack detected&quot;</li><li><strong>Description</strong>: The nonce has already been consumed, indicating a potential replay attack</li><li><strong>Common Causes</strong>: Duplicate request submission, replay attack attempt</li><li><strong>Solution</strong>: Generate a new nonce for each request</li></ul><h5 id="invalidnonceformat" tabindex="-1">InvalidNonceFormat <a class="header-anchor" href="#invalidnonceformat" aria-label="Permalink to &quot;InvalidNonceFormat&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Invalid nonce format&quot;</li><li><strong>Description</strong>: The nonce does not follow the expected format</li><li><strong>Common Causes</strong>: Corrupted nonce, manually crafted invalid nonce</li><li><strong>Solution</strong>: Use the standard nonce generation method</li></ul><h5 id="invalidnoncetimestamp" tabindex="-1">InvalidNonceTimestamp <a class="header-anchor" href="#invalidnoncetimestamp" aria-label="Permalink to &quot;InvalidNonceTimestamp&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Nonce timestamp is invalid or expired&quot;</li><li><strong>Description</strong>: The timestamp embedded in the nonce is invalid or outside the valid time window</li><li><strong>Common Causes</strong>: System time drift, expired nonce, or tampered timestamp</li><li><strong>Solution</strong>: Synchronize system time and generate a fresh nonce</li></ul><h4 id="_7-refresh-token-errors" tabindex="-1">7. Refresh Token Errors <a class="header-anchor" href="#_7-refresh-token-errors" aria-label="Permalink to &quot;7. Refresh Token Errors&quot;">​</a></h4><h5 id="refreshtokennotfound" tabindex="-1">RefreshTokenNotFound <a class="header-anchor" href="#refreshtokennotfound" aria-label="Permalink to &quot;RefreshTokenNotFound&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Refresh token not found or expired&quot;</li><li><strong>Description</strong>: The refresh token does not exist or has expired</li><li><strong>Common Causes</strong>: Never issued, expired, or revoked</li><li><strong>Solution</strong>: User must re-authenticate to get a new refresh token</li></ul><h5 id="refreshtokeninvaliddata" tabindex="-1">RefreshTokenInvalidData <a class="header-anchor" href="#refreshtokeninvaliddata" aria-label="Permalink to &quot;RefreshTokenInvalidData&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Invalid refresh token data&quot;</li><li><strong>Description</strong>: The stored refresh token data is corrupted or malformed</li><li><strong>Common Causes</strong>: Storage corruption, tampering, or serialization error</li><li><strong>Solution</strong>: User must re-authenticate</li></ul><h5 id="refreshtokenmissingloginid" tabindex="-1">RefreshTokenMissingLoginId <a class="header-anchor" href="#refreshtokenmissingloginid" aria-label="Permalink to &quot;RefreshTokenMissingLoginId&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Missing login_id in refresh token&quot;</li><li><strong>Description</strong>: The refresh token is missing the required login_id field</li><li><strong>Common Causes</strong>: Data corruption or incomplete token generation</li><li><strong>Solution</strong>: Generate a new refresh token</li></ul><h5 id="refreshtokeninvalidexpiretime" tabindex="-1">RefreshTokenInvalidExpireTime <a class="header-anchor" href="#refreshtokeninvalidexpiretime" aria-label="Permalink to &quot;RefreshTokenInvalidExpireTime&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Invalid expire time format in refresh token&quot;</li><li><strong>Description</strong>: The expiration time in refresh token cannot be parsed</li><li><strong>Common Causes</strong>: Incorrect date format or corrupted data</li><li><strong>Solution</strong>: Generate a new refresh token with correct format</li></ul><h4 id="_8-token-validation-errors" tabindex="-1">8. Token Validation Errors <a class="header-anchor" href="#_8-token-validation-errors" aria-label="Permalink to &quot;8. Token Validation Errors&quot;">​</a></h4><h5 id="tokenempty" tabindex="-1">TokenEmpty <a class="header-anchor" href="#tokenempty" aria-label="Permalink to &quot;TokenEmpty&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Token is empty&quot;</li><li><strong>Description</strong>: No token value provided</li><li><strong>Common Causes</strong>: Empty string passed as token</li><li><strong>Solution</strong>: Provide a valid token value</li></ul><h5 id="tokentooshort" tabindex="-1">TokenTooShort <a class="header-anchor" href="#tokentooshort" aria-label="Permalink to &quot;TokenTooShort&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Token is too short&quot;</li><li><strong>Description</strong>: Token length is below minimum required (8 characters)</li><li><strong>Common Causes</strong>: Truncated or invalid token</li><li><strong>Solution</strong>: Provide a complete valid token</li></ul><h5 id="loginidnotnumber" tabindex="-1">LoginIdNotNumber <a class="header-anchor" href="#loginidnotnumber" aria-label="Permalink to &quot;LoginIdNotNumber&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Login ID is not a valid number&quot;</li><li><strong>Description</strong>: Failed to parse login ID as a numeric value</li><li><strong>Common Causes</strong>: Non-numeric login ID when numeric is expected</li><li><strong>Solution</strong>: Ensure login ID format matches expected type</li></ul><h4 id="_9-oauth2-errors" tabindex="-1">9. OAuth2 Errors <a class="header-anchor" href="#_9-oauth2-errors" aria-label="Permalink to &quot;9. OAuth2 Errors&quot;">​</a></h4><h5 id="oauth2clientnotfound" tabindex="-1">OAuth2ClientNotFound <a class="header-anchor" href="#oauth2clientnotfound" aria-label="Permalink to &quot;OAuth2ClientNotFound&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;OAuth2 client not found&quot;</li><li><strong>Description</strong>: The OAuth2 client ID does not exist</li><li><strong>Common Causes</strong>: Unregistered client or incorrect client ID</li><li><strong>Solution</strong>: Register the client or verify client ID</li></ul><h5 id="oauth2invalidcredentials" tabindex="-1">OAuth2InvalidCredentials <a class="header-anchor" href="#oauth2invalidcredentials" aria-label="Permalink to &quot;OAuth2InvalidCredentials&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Invalid client credentials&quot;</li><li><strong>Description</strong>: Client ID and secret combination is invalid</li><li><strong>Common Causes</strong>: Wrong secret, mistyped credentials</li><li><strong>Solution</strong>: Verify client credentials are correct</li></ul><h5 id="oauth2clientidmismatch" tabindex="-1">OAuth2ClientIdMismatch <a class="header-anchor" href="#oauth2clientidmismatch" aria-label="Permalink to &quot;OAuth2ClientIdMismatch&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Client ID mismatch&quot;</li><li><strong>Description</strong>: Client ID doesn&#39;t match the expected value</li><li><strong>Common Causes</strong>: Using wrong client ID for authorization code or refresh token</li><li><strong>Solution</strong>: Use the correct client ID that initiated the flow</li></ul><h5 id="oauth2redirecturimismatch" tabindex="-1">OAuth2RedirectUriMismatch <a class="header-anchor" href="#oauth2redirecturimismatch" aria-label="Permalink to &quot;OAuth2RedirectUriMismatch&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Redirect URI mismatch&quot;</li><li><strong>Description</strong>: Redirect URI doesn&#39;t match registered URIs</li><li><strong>Common Causes</strong>: URI not in whitelist, typo in URI</li><li><strong>Solution</strong>: Use a registered redirect URI</li></ul><h5 id="oauth2codenotfound" tabindex="-1">OAuth2CodeNotFound <a class="header-anchor" href="#oauth2codenotfound" aria-label="Permalink to &quot;OAuth2CodeNotFound&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Authorization code not found or expired&quot;</li><li><strong>Description</strong>: Authorization code doesn&#39;t exist or has expired</li><li><strong>Common Causes</strong>: Code already used, expired (typically 10 minutes)</li><li><strong>Solution</strong>: Request a new authorization code</li></ul><h5 id="oauth2accesstokennotfound" tabindex="-1">OAuth2AccessTokenNotFound <a class="header-anchor" href="#oauth2accesstokennotfound" aria-label="Permalink to &quot;OAuth2AccessTokenNotFound&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Access token not found or expired&quot;</li><li><strong>Description</strong>: OAuth2 access token not found or expired</li><li><strong>Common Causes</strong>: Token expired (typically 1 hour), revoked, or never issued</li><li><strong>Solution</strong>: Refresh token or re-authorize</li></ul><h5 id="oauth2refreshtokennotfound" tabindex="-1">OAuth2RefreshTokenNotFound <a class="header-anchor" href="#oauth2refreshtokennotfound" aria-label="Permalink to &quot;OAuth2RefreshTokenNotFound&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Refresh token not found or expired&quot;</li><li><strong>Description</strong>: OAuth2 refresh token not found or expired</li><li><strong>Common Causes</strong>: Token expired (typically 30 days), revoked, or never issued</li><li><strong>Solution</strong>: User must re-authorize</li></ul><h5 id="oauth2invalidrefreshtoken" tabindex="-1">OAuth2InvalidRefreshToken <a class="header-anchor" href="#oauth2invalidrefreshtoken" aria-label="Permalink to &quot;OAuth2InvalidRefreshToken&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Invalid refresh token data&quot;</li><li><strong>Description</strong>: Refresh token data is corrupted or invalid</li><li><strong>Common Causes</strong>: Data corruption, tampering</li><li><strong>Solution</strong>: Re-authorize to get new tokens</li></ul><h5 id="oauth2invalidscope" tabindex="-1">OAuth2InvalidScope <a class="header-anchor" href="#oauth2invalidscope" aria-label="Permalink to &quot;OAuth2InvalidScope&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Invalid scope data&quot;</li><li><strong>Description</strong>: Scope data is invalid or corrupted</li><li><strong>Common Causes</strong>: Invalid scope format, unauthorized scope request</li><li><strong>Solution</strong>: Request valid scopes only</li></ul><h4 id="_10-system-errors" tabindex="-1">10. System Errors <a class="header-anchor" href="#_10-system-errors" aria-label="Permalink to &quot;10. System Errors&quot;">​</a></h4><h5 id="storageerror" tabindex="-1">StorageError <a class="header-anchor" href="#storageerror" aria-label="Permalink to &quot;StorageError&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Storage error: {details}&quot;</li><li><strong>Description</strong>: Error occurred while accessing storage backend</li><li><strong>Common Causes</strong>: Database connection failure, Redis unavailable, network issues</li><li><strong>Solution</strong>: Check storage backend status and connectivity</li></ul><h5 id="configerror" tabindex="-1">ConfigError <a class="header-anchor" href="#configerror" aria-label="Permalink to &quot;ConfigError&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Configuration error: {details}&quot;</li><li><strong>Description</strong>: Configuration is invalid or missing</li><li><strong>Common Causes</strong>: Missing required config, invalid config values</li><li><strong>Solution</strong>: Review and fix configuration</li></ul><h5 id="serializationerror" tabindex="-1">SerializationError <a class="header-anchor" href="#serializationerror" aria-label="Permalink to &quot;SerializationError&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Serialization error: {details}&quot;</li><li><strong>Description</strong>: Failed to serialize or deserialize data</li><li><strong>Common Causes</strong>: Data structure mismatch, corrupted JSON</li><li><strong>Solution</strong>: Check data format and structure</li></ul><h5 id="internalerror" tabindex="-1">InternalError <a class="header-anchor" href="#internalerror" aria-label="Permalink to &quot;InternalError&quot;">​</a></h5><ul><li><strong>Message</strong>: &quot;Internal error: {details}&quot;</li><li><strong>Description</strong>: An unexpected internal error occurred</li><li><strong>Common Causes</strong>: Programming error, unexpected state</li><li><strong>Solution</strong>: Report to developers with error details</li></ul><hr><h2 id="summary-总结" tabindex="-1">Summary | 总结 <a class="header-anchor" href="#summary-总结" aria-label="Permalink to &quot;Summary | 总结&quot;">​</a></h2><p>This document provides comprehensive error documentation in Chinese and English for sa-token-rust. Each error includes:</p><ul><li>Error message</li><li>Detailed description</li><li>Common causes</li><li>Solutions</li></ul><p>For developers integrating sa-token-rust, this guide helps understand and handle errors effectively.</p><hr><p><strong>Version</strong>: 0.1.14<br><strong>Last Updated</strong>: 2026-05-07</p>',85)])])}const m=o(i,[["render",a]]);export{g as __pageData,m as default};
